#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

struct AlwaysTriggerResult {
    int recomputeCountAfterInit;
    int recomputeCountAfterDuplicateWrite;
};

AlwaysTriggerResult test_always_trigger(int initialValue) {
    // 1. Create a reactive variable using reaction::var with initialValue
    auto reactiveVar = reaction::var(initialValue);

    // 2. Create a counter variable to track recomputation count
    int recomputeCounter = 0;

    // 3. Create an AlwaysTrig calculation using reaction::calc with a lambda that doubles the value and increments counter
    auto alwaysTrigCalc = reaction::calc<reaction::AlwaysTrig>([&]() {
        // Double the value from the reactive variable
        int doubledValue = reactiveVar() * 2;
        // Increment the counter each time this calculation runs
        recomputeCounter++;
        return doubledValue;
    });

    // 4. Store the counter value after initialization
    int countAfterInit = recomputeCounter;

    // 5. Write the same value back to the reactive variable using value() method
    reactiveVar.value(initialValue);

    // 6. Store the counter value after duplicate write
    int countAfterDuplicateWrite = recomputeCounter;

    // 7. Force evaluation of calculation to avoid unused variable warnings
    // Call the calculation to ensure it's evaluated
    int finalValue = alwaysTrigCalc();

    // 8. Return the result struct with both counter values
    return AlwaysTriggerResult{
        .recomputeCountAfterInit = countAfterInit,
        .recomputeCountAfterDuplicateWrite = countAfterDuplicateWrite
    };
}

}  // namespace test_reaction
```

