#pragma once

#include <reaction/core/resource.h>
#include <array>

namespace test_reaction {

struct ResourceSBOState {
    bool smallTypeUsesSBO;
    bool largeTypeUsesSBO;
};

ResourceSBOState test_resource_sbo() {
    // 1. Define small type that fits within SBO buffer (<= 64 bytes)
    struct SmallStruct {
        int x, y;
        SmallStruct(int x = 0, int y = 0) : x(x), y(y) {}
        bool operator==(const SmallStruct& other) const {
            return x == other.x && y == other.y;
        }
        bool operator!=(const SmallStruct& other) const {
            return !(*this == other);
        }
    };

    // 2. Define large type that exceeds SBO buffer (> 64 bytes)
    struct LargeStruct {
        char data[128]; // 128 bytes > 64 byte SBO limit
        LargeStruct(char fill = 'A') {
            std::fill(data, data + 128, fill);
        }
    };

    // 3. Create Resource instances for both types
    reaction::Resource<SmallStruct> smallResource(SmallStruct{10, 20});
    reaction::Resource<LargeStruct> largeResource(LargeStruct{'B'});

    // 4. Query SBO usage status using isUsingSBO() method
    bool smallUsesSBO = smallResource.isUsingSBO();
    bool largeUsesSBO = largeResource.isUsingSBO();

    // 5. Return the results in ResourceSBOState struct
    return ResourceSBOState{
        .smallTypeUsesSBO = smallUsesSBO,
        .largeTypeUsesSBO = largeUsesSBO
    };
}

}  // namespace test_reaction
```

