inline AtomicCompoundSnapshot test_atomic_compound_assign() {
    using namespace reaction;

    // 1. Create reactive variable with initial value 1
    auto reactive_var = var(1);

    // 2. Create counter to track calculation evaluations
    std::atomic<int> calc_counter{0};

    // 3. Create calculation that depends on reactive variable and increments counter
    auto calc_result = calc([&]() -> int {
        // This calculation will be re-evaluated when reactive_var changes
        calc_counter.fetch_add(1, std::memory_order_relaxed);
        return reactive_var.get();
    });

    // Force initial evaluation of the calculation
